  "lessonText": "Learn the basics of variables and data types in Python.",
  "data": {
    "cards": [
      {
        "front": "What is a variable?",
        "back": "A variable is a named location in memory used to store data.",
        "icon": "📦"
      },
      {
        "front": "Common data types in Python?",
        "back": "Integers, floats, strings, and booleans are common data types.",
        "icon": "🔢"
      },
      {
        "front": "How to declare a variable?",
        "back": "Use the syntax: variable_name = value.",
        "icon": "✍️"
      },
      {
        "front": "What is dynamic typing?",
        "back": "Dynamic typing allows variables to change type during execution.",
        "icon": "🔄"
      }
    ]
  }
}
